#include<bits/stdc++.h>
using namespace std;
vector<long long> mp[300010];
long long val[300010][51],f[300010][21],d[300010];
const long long mod=998244353;
long long fastpow(long long x,long long y)
{
    long long ans=1;
    while(y)
    {
        if(y%2==1)
        {
            ans=ans*x%mod;
        }
        x=x*x%mod;
        y/=2;
    }
    return ans;
}
void dfs(long long x,long long fa=0)
{
    f[x][0]=fa;
    for(long long i=1;i<=20;i++)
    {
        f[x][i]=f[f[x][i-1]][i-1];
    }
    for(long long i:mp[x])
    {
        if(i!=fa)
        {
            d[i]=d[x]+1;
            for(long long j=1;j<=50;j++)
            {
                val[i][j]=(val[x][j]+fastpow(d[i],j))%mod;
            }
            dfs(i,x);
        }
    }
}
long long lg[300010];
long long lca(long long x,long long y)
{
    if(d[x]<d[y])
    {
        swap(x,y);
    }
    while(d[x]>d[y])
    {
        x=f[x][lg[d[x]-d[y]]];
    }
    if(x==y)
    {
        return x;
    }
    for(long long i=lg[d[x]+1];i>=0;i--)
    {
        if(f[x][i]!=f[y][i])
        {
            x=f[x][i];
            y=f[y][i];
        }
    }
    return f[x][0];
}
int main()
{
    long long n;
    scanf("%lld",&n);
    for(long long i=2;i<=n;i++)
    {
        lg[i]=lg[i/2]+1;
    }
    for(long long i=1;i<n;i++)
    {
        long long x,y;
        scanf("%lld%lld",&x,&y);
        mp[x].push_back(y);
        mp[y].push_back(x);
    }
    dfs(1);
    long long m;
    scanf("%lld",&m);
    while(m--)
    {
        long long x,y,k;
        scanf("%lld%lld%lld",&x,&y,&k);
        long long l=lca(x,y);
        printf("%lld\n",((val[x][k]+val[y][k]-val[l][k]-val[f[l][0]][k])%mod+mod)%mod);
    }
    return 0;
}
